import{_ as a,o as t,c as n,ag as s}from"./chunks/framework.NIzFHKo_.js";const h=JSON.parse('{"title":"Placement Rules","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/30_data/130_placement_rules.md","filePath":"10_core/30_data/130_placement_rules.md"}'),o={name:"10_core/30_data/130_placement_rules.md"};function i(r,e,c,l,d,p){return t(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="placement-rules" tabindex="-1">Placement Rules <a class="header-anchor" href="#placement-rules" aria-label="Permalink to &quot;Placement Rules&quot;">​</a></h1><p>Placement rules define where every type of object belongs. When placement is ambiguous, escalate to an ADR.</p><p>Current active doctrine is document-first and runtime-first: QiAccess Start documentation lives in Markdown/YAML, qiserver owns local runtime execution, QiNexus remains the storage backbone, and Supabase-specific placement remains legacy/reference-only or future/conditional unless a specific job requires it.</p><h2 id="the-primary-rule" tabindex="-1">The Primary Rule <a class="header-anchor" href="#the-primary-rule" aria-label="Permalink to &quot;The Primary Rule&quot;">​</a></h2><blockquote><p>Every object has exactly one canonical domain.</p></blockquote><p>If you cannot answer &quot;which domain or governed container owns this object&#39;s lifecycle?&quot; - the object is not ready to be placed.</p><h2 id="placement-decision-tree" tabindex="-1">Placement Decision Tree <a class="header-anchor" href="#placement-decision-tree" aria-label="Permalink to &quot;Placement Decision Tree&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Is it a file or ingested record?          -&gt; qiarchive</span></span>
<span class="line"><span>Is it a legal/operational case?           -&gt; qicase</span></span>
<span class="line"><span>Is it a calendar event or time record?    -&gt; qichronicle</span></span>
<span class="line"><span>Is it published content or a post?        -&gt; qicms</span></span>
<span class="line"><span>Is it a household expense or chore?       -&gt; qihome</span></span>
<span class="line"><span>Is it a note or local knowledge record?   -&gt; qiknowledge</span></span>
<span class="line"><span>Is it a tax return or related document?   -&gt; qitax</span></span>
<span class="line"><span>Is it a secure document or contract?      -&gt; qivault</span></span>
<span class="line"><span>Is it an AI session or memory record?     -&gt; qially (future/conditional)</span></span>
<span class="line"><span>Is it a system job or worker event?       -&gt; qisys</span></span>
<span class="line"><span>Is it a graph node or derived edge?       -&gt; qigraph (future/conditional)</span></span>
<span class="line"><span>Is it a modular config or module registry record? -&gt; qione (reference only)</span></span>
<span class="line"><span>Is it a tenant, member, or RBAC record?   -&gt; qione (Platform-Future only)</span></span>
<span class="line"><span>Is it an email account integration param? -&gt; qione (reference only)</span></span>
<span class="line"><span>Is it an ingested email message/thread?   -&gt; qiarchive</span></span>
<span class="line"><span>Is it an email sync event or cursor?      -&gt; qisys</span></span>
<span class="line"><span>Is it a global auth record?               -&gt; future auth layer if one is explicitly activated</span></span></code></pre></div><h2 id="rules-for-new-objects" tabindex="-1">Rules for New Objects <a class="header-anchor" href="#rules-for-new-objects" aria-label="Permalink to &quot;Rules for New Objects&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Rule</th><th>Requirement</th></tr></thead><tbody><tr><td>Every object must have</td><td>A canonical ID</td></tr><tr><td>Every domain-scoped object must have</td><td>A <code>owner_user_id</code> FK</td></tr><tr><td>Every file-derived object or email attachment must have</td><td>An <code>archive_id</code> FK</td></tr><tr><td>Every object must have</td><td>A status field</td></tr><tr><td>Every mutable object must have</td><td><code>created_at</code> + <code>updated_at</code> timestamps</td></tr></tbody></table><h2 id="domain-specific-guardrails" tabindex="-1">Domain-Specific Guardrails <a class="header-anchor" href="#domain-specific-guardrails" aria-label="Permalink to &quot;Domain-Specific Guardrails&quot;">​</a></h2><ul><li><strong>Email</strong>: Do not create a top-level <code>qiemail</code> schema unless a future ADR explicitly approves it. Email should be modeled as an integration path into the canonical Spine, relying on <code>qione</code> for configuration only if that relational layer is reactivated, <code>qiarchive</code> for content, <code>qisys</code> for sync state, and <code>qially</code> for semantic memory only if that future layer is activated. Durable, secure email attachments may be promoted to <code>qivault</code>.</li></ul><h2 id="what-belongs-in-public" tabindex="-1">What Belongs in <code>public</code> <a class="header-anchor" href="#what-belongs-in-public" aria-label="Permalink to &quot;What Belongs in \`public\`&quot;">​</a></h2><p>Only:</p><ul><li><code>profiles</code> — user profile data tied to <code>auth.users</code></li><li>Legacy tables retained for compatibility (<code>todos</code>, <code>nods_page</code>)</li></ul><p><strong>No new tables should be created in <code>public</code> schema.</strong></p><h2 id="object-naming-contract" tabindex="-1">Object Naming Contract <a class="header-anchor" href="#object-naming-contract" aria-label="Permalink to &quot;Object Naming Contract&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{domain}_{name}_{QXXXXXX}.ext</span></span></code></pre></div><ul><li><code>domain</code> = lowercase domain prefix (e.g. <code>bbr4821</code>)</li><li><code>name</code> = normalized, human-readable base</li><li><code>QXXXXXX</code> = Q + 6 uppercase hex short code assigned by QiArchive</li><li><code>.ext</code> = lowercase file extension</li></ul>`,19)])])}const m=a(o,[["render",i]]);export{h as __pageData,m as default};
